# Write helper: mcts/encoding.py
mcts_encoding_py_content = '"""Sparse state and action encoding for the MCTS policy/value network.\n\nThe state encoder emits 24 words: two players times eight bench words (sharing\npositions within each player\'s block), two active words, two player-state words,\nthen hand, own-deck, stadium, and misc words. Continuous scales are HP/400,\ndeck and discard counts/60, hand/8, bench/5, discarded cards weighted 0.25,\nand attached Energy weighted 0.5. The misc word contains turn and first-player\nfeatures.\n\nAction features start with 14 fixed slots, followed by the attack block at offset\n14, then card blocks sized ``(1 + 8 roles + 48 contexts) * card_count``.\n"""\n\ntry:\n    from base_agent import get_card as get_card_helper\nexcept ImportError:\n    from agents.base import get_card as get_card_helper\nfrom cg.api import Card, Observation, OptionType, PlayerState, Pokemon\n\nfrom .model import card_count, decoder_attack_offset, decoder_card_offset, decoder_main_feature\n\n\nclass SparseVector:\n    def __init__(self):\n        self.index = []\n        self.value = []\n        self.offset = []\n        self.pos = 0\n\n    def add(self, index: int, value: float | int | bool):\n        value = float(value)\n        if value != 0.0:\n            self.index.append(self.pos + index)\n            self.value.append(value)\n\n    def add_pos(self, pos: int):\n        self.pos += pos\n\n    def add_single(self, value: float | int | bool):\n        value = float(value)\n        if value != 0.0:\n            self.index.append(self.pos)\n            self.value.append(value)\n        self.pos += 1\n\n    def word_start(self):\n        self.offset.append(len(self.index))\n\n\ndef add_card(sv: SparseVector, card: Card | Pokemon | None):\n    if card is not None:\n        sv.add(card.id, 1)\n    sv.add_pos(card_count)\n\n\ndef add_cards(sv: SparseVector, cards: list[Card] | None, value: float):\n    if cards is not None:\n        for card in cards:\n            sv.add(card.id, value)\n    sv.add_pos(card_count)\n\n\ndef add_pokemon(sv: SparseVector, poke: Pokemon | None):\n    if poke is None:\n        sv.add_single(1)\n        sv.add_pos(1 + 3 * card_count)\n    else:\n        sv.add_single(0)\n        sv.add_single(poke.hp / 400.0)\n        add_card(sv, poke)\n        add_cards(sv, poke.tools, 1.0)\n        add_cards(sv, poke.energyCards, 0.5)\n\n\ndef add_player(sv: SparseVector, ps: PlayerState):\n    sv.add_single(ps.deckCount / 60.0)\n    sv.add_single(len(ps.discard) / 60.0)\n    sv.add_single(ps.handCount / 8.0)\n    sv.add_single(len(ps.bench) / 5.0)\n    sv.add(len(ps.prize), 1)\n    sv.add_pos(7)\n\n    sv.add_single(ps.poisoned)\n    sv.add_single(ps.burned)\n    sv.add_single(ps.asleep)\n    sv.add_single(ps.paralyzed)\n    sv.add_single(ps.confused)\n    add_cards(sv, ps.discard, 0.25)\n\n\ndef encode_state(obs: Observation, your_deck: list[int]) -> SparseVector:\n    your_index = obs.current.yourIndex\n    state = obs.current\n\n    sv = SparseVector()\n    for i in range(2):\n        ps = state.players[i ^ your_index]\n        for j in range(8):\n            sv.word_start()\n            pos = sv.pos\n            if j < len(ps.bench):\n                add_pokemon(sv, ps.bench[j])\n            else:\n                add_pokemon(sv, None)\n            if j != 7:\n                sv.pos = pos\n\n    for i in range(2):\n        ps = state.players[i ^ your_index]\n        sv.word_start()\n        if ps.active:\n            add_pokemon(sv, ps.active[0])\n        else:\n            add_pokemon(sv, None)\n\n    for i in range(2):\n        ps = state.players[i ^ your_index]\n        sv.word_start()\n        add_player(sv, ps)\n\n    sv.word_start()\n    add_cards(sv, state.players[your_index].hand, 0.25)\n\n    sv.word_start()\n    for id in your_deck:\n        sv.add(id, 0.25)\n    sv.add_pos(card_count)\n\n    sv.word_start()\n    add_cards(sv, state.stadium, 1.0)\n\n    sv.word_start()\n    sv.add_single(1)\n    sv.add_single(state.turn / 10.0)\n    sv.add_single(state.firstPlayer == your_index)\n    return sv\n\n\ndef add_role_card_feature(sv: SparseVector, feature_index: int, card: Card | Pokemon | None):\n    if card is not None:\n        sv.add(decoder_card_offset + feature_index * card_count + card.id, 1)\n\n\ndef add_context_card_id(sv: SparseVector, context: int, card_id: int):\n    sv.add(decoder_card_offset + (decoder_main_feature + context) * card_count + card_id, 1)\n\n\ndef add_context_card(sv: SparseVector, context: int, card: Card | Pokemon | None):\n    if card is not None:\n        add_context_card_id(sv, context, card.id)\n\n\ndef encode_actions(obs: Observation, actions: list[list[int]]) -> SparseVector:\n    sv = SparseVector()\n    your_index = obs.current.yourIndex\n    ps = obs.current.players[your_index]\n    context = int(obs.select.context) if hasattr(obs.select.context, "value") else int(obs.select.context)\n\n    for action in actions:\n        sv.word_start()\n        if not action:\n            sv.add(0, 1)\n            continue\n\n        for i in action:\n            o = obs.select.option[i]\n            o_type = int(o.type) if hasattr(o.type, "value") else int(o.type)\n            if o_type == OptionType.END:\n                sv.add(1, 1)\n            elif o_type == OptionType.YES:\n                sv.add(2, 1)\n            elif o_type == OptionType.NO:\n                sv.add(3, 1)\n            elif o_type == OptionType.SPECIAL_CONDITION:\n                sv.add(4 + int(o.specialConditionType), 1)\n            elif o_type == OptionType.NUMBER:\n                sv.add(9 + min(o.number, 4), 1)\n            elif o_type == OptionType.ATTACK:\n                sv.add(decoder_attack_offset + o.attackId, 1)\n            elif o_type == OptionType.PLAY:\n                add_role_card_feature(sv, 0, ps.hand[o.index] if ps.hand else None)\n            elif o_type == OptionType.ATTACH:\n                add_role_card_feature(sv, 1, get_card_helper(obs, int(o.area), o.index, your_index))\n                add_role_card_feature(sv, 2, get_card_helper(obs, int(o.inPlayArea), o.inPlayIndex, your_index))\n            elif o_type == OptionType.EVOLVE:\n                add_role_card_feature(sv, 3, get_card_helper(obs, int(o.area), o.index, your_index))\n                add_role_card_feature(sv, 4, get_card_helper(obs, int(o.inPlayArea), o.inPlayIndex, your_index))\n            elif o_type == OptionType.ABILITY:\n                add_role_card_feature(sv, 5, get_card_helper(obs, int(o.area), o.index, your_index))\n            elif o_type == OptionType.DISCARD:\n                add_role_card_feature(sv, 6, get_card_helper(obs, int(o.area), o.index, your_index))\n            elif o_type == OptionType.RETREAT:\n                add_role_card_feature(sv, 7, ps.active[0] if ps.active else None)\n            elif o_type == OptionType.CARD:\n                add_context_card(sv, context, get_card_helper(obs, int(o.area), o.index, o.playerIndex))\n            elif o_type == OptionType.TOOL_CARD:\n                card = get_card_helper(obs, int(o.area), o.index, o.playerIndex)\n                if card and hasattr(card, "tools") and o.toolIndex < len(card.tools):\n                    add_context_card(sv, context, card.tools[o.toolIndex])\n            elif o_type in (OptionType.ENERGY_CARD, OptionType.ENERGY):\n                card = get_card_helper(obs, int(o.area), o.index, o.playerIndex)\n                if card and hasattr(card, "energyCards") and o.energyIndex < len(card.energyCards):\n                    add_context_card(sv, context, card.energyCards[o.energyIndex])\n            elif o_type == OptionType.SKILL:\n                add_context_card_id(sv, context, o.cardId)\n    return sv\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/encoding.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/encoding.py"), "w") as f:
    f.write(mcts_encoding_py_content)

# Write helper: mcts/model.py
mcts_model_py_content = '"""Transformer policy/value model for sparse Pokémon TCG observations.\n\nThe value path uses an EmbeddingBag sparse input, transformer encoder, and scalar\nvalue head. The policy path uses a decoder EmbeddingBag and cross-attention layers\nover the encoded state before its scalar action head. ``MODEL_ARGS`` contains\n``(d_model, num_heads, d_feedforward, encoder_layers, decoder_layers)``;\n``num_heads`` must divide ``d_model``.\n"""\n\nimport torch\n\nfrom cg.api import all_attack, all_card_data\n\ntry:\n    all_card = all_card_data()\n    card_count = max(all_card, key=lambda c: c.cardId).cardId + 1\n    attack_count = max(all_attack(), key=lambda a: a.attackId).attackId + 1\nexcept Exception:\n    card_count = 2000\n    attack_count = 2000\n\nnum_words_encoder = 24\nencoder_size = 22000\ndecoder_main_feature = 8\ndecoder_attack_offset = 14\ndecoder_card_offset = decoder_attack_offset + attack_count\ndecoder_size = decoder_card_offset + (1 + decoder_main_feature + 48) * card_count\n\n# (d_model, num_heads, d_feedforward, n_encoder_layers, n_decoder_layers).\n# Single source of truth: training and inference both build PolicyValueNet\n# from this, so checkpoints always match. num_heads must divide d_model.\nMODEL_ARGS = (256, 4, 512, 2, 2)\n\n\ndef _layer_count(state_dict, prefix: str, suffix: str) -> int:\n    found = []\n    for key in state_dict:\n        if key.startswith(prefix) and key.endswith(suffix):\n            try:\n                found.append(int(key[len(prefix) :].split(".", 1)[0]))\n            except ValueError:\n                pass\n    return max(found) + 1 if found else 0\n\n\ndef model_args_from_state_dict(state_dict) -> tuple[int, int, int, int, int]:\n    d_model = int(state_dict["encoder_bag.weight"].shape[1])\n    d_feedforward = int(state_dict["encoder.layers.0.linear1.weight"].shape[0])\n    num_heads = MODEL_ARGS[1] if d_model % MODEL_ARGS[1] == 0 else 4\n    return (\n        d_model,\n        num_heads,\n        d_feedforward,\n        _layer_count(state_dict, "encoder.layers.", ".linear1.weight"),\n        _layer_count(state_dict, "decoder.", ".fc1.weight"),\n    )\n\n\nclass DecoderLayer(torch.nn.Module):\n    def __init__(self, d_model: int, num_heads: int, d_feedforward: int):\n        super().__init__()\n        self.attention = torch.nn.MultiheadAttention(d_model, num_heads)\n        self.fc1 = torch.nn.Linear(d_model, d_feedforward)\n        self.fc2 = torch.nn.Linear(d_feedforward, d_model)\n        self.norm1 = torch.nn.LayerNorm(d_model)\n        self.norm2 = torch.nn.LayerNorm(d_model)\n\n    def forward(self, x: torch.Tensor, encoder_out: torch.Tensor) -> torch.Tensor:\n        y, _ = self.attention(x, encoder_out, encoder_out, need_weights=False)\n        res = self.norm1(x + y)\n        y = self.fc1(res)\n        y = torch.nn.functional.relu(y)\n        y = self.fc2(y)\n        return self.norm2(res + y)\n\n\nclass PolicyValueNet(torch.nn.Module):\n    def __init__(\n        self, d_model: int, num_heads: int, d_feedforward: int, num_layers_encoder: int, num_layers_decoder: int\n    ):\n        super().__init__()\n        self.d_model = d_model\n        self.encoder_bag = torch.nn.EmbeddingBag(encoder_size, d_model, mode="sum")\n        encoder_layer = torch.nn.TransformerEncoderLayer(d_model, num_heads, d_feedforward, 0)\n        self.encoder = torch.nn.TransformerEncoder(encoder_layer, num_layers_encoder, enable_nested_tensor=False)\n        self.encoder_fc = torch.nn.Linear(d_model, 1)\n        self.decoder_bag = torch.nn.EmbeddingBag(decoder_size, d_model, mode="sum")\n        self.decoder = torch.nn.ModuleList()\n        for _ in range(num_layers_decoder):\n            self.decoder.append(DecoderLayer(d_model, num_heads, d_feedforward))\n        self.decoder_fc = torch.nn.Linear(d_model, 1)\n\n    def forward(self, index_encoder, value_encoder, offset_encoder, index_decoder, value_decoder, offset_decoder):\n        v = self.encoder_bag(index_encoder, offset_encoder, value_encoder)\n        v = v.reshape(-1, num_words_encoder, self.d_model).transpose(0, 1)\n        batch_size = v.size(1)\n        encoder_out = self.encoder(v)\n        v = self.encoder_fc(encoder_out)\n        v = torch.tanh(v.mean(0))\n\n        p = self.decoder_bag(index_decoder, offset_decoder, value_decoder)\n        p = p.reshape(batch_size, -1, self.d_model).transpose(0, 1)\n        for layer in self.decoder:\n            p = layer(p, encoder_out)\n        p = self.decoder_fc(p)\n        p = p.transpose(0, 1).view(batch_size, -1)\n        p = torch.tanh(p)\n        return (v, p)\n\n\nMyModel = PolicyValueNet\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/model.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/model.py"), "w") as f:
    f.write(mcts_model_py_content)

# Write helper: mcts/search.py
mcts_search_py_content = '"""Shared MCTS tree mechanics.\n\nSelection is PUCT-style: ``q + 0.4*sqrt(N_parent)*prior/(1+n)``. Priors use\n``exp(policy*10)`` and candidate combinations are capped at 64 to bound inference\nlatency on large multi-select prompts. Values use the root player\'s perspective:\n+1 is a win for ``your_index`` and values are negated at opponent-to-move nodes.\n\nInference determinizes hidden information on every move: the agent samples its own\nunknown deck and Prize cards, while unknown opponent cards use Snorlax card 1072 as\na filler. That determinization is prepared by ``agent.py`` before this module builds\nthe search tree.\n"""\n\nimport math\nfrom collections.abc import Callable\n\nimport torch\n\nfrom cg.api import Observation, SearchState\n\nfrom .encoding import SparseVector\nfrom .model import PolicyValueNet\n\n# The cg API exposes match results as raw integers: player 0, player 1, or draw.\nRESULT_DRAW = 2\nEXPLORATION_C = 0.4\nPOLICY_TEMPERATURE = 10.0\nMAX_ACTION_COMBINATIONS = 64\n\n\ndef evaluate_position(sv_enc: SparseVector, sv_dec: SparseVector, model: PolicyValueNet) -> tuple[float, list[float]]:\n    device = next(model.parameters()).device\n    with torch.no_grad():\n        value, policy = model(\n            torch.tensor(sv_enc.index, dtype=torch.int32, device=device),\n            torch.tensor(sv_enc.value, dtype=torch.float32, device=device),\n            torch.tensor(sv_enc.offset, dtype=torch.int32, device=device),\n            torch.tensor(sv_dec.index, dtype=torch.int32, device=device),\n            torch.tensor(sv_dec.value, dtype=torch.float32, device=device),\n            torch.tensor(sv_dec.offset, dtype=torch.int32, device=device),\n        )\n    return (value.tolist()[0][0], policy.tolist()[0])\n\n\nclass Child:\n    def __init__(self, select: list[int], prob: float):\n        self.node = None\n        self.select = select\n        self.prob = prob\n\n\nclass Node:\n    def __init__(self, parent: "Node | None", state: SearchState):\n        self.value = -2.0\n        self.total = 0.0\n        self.visit = 0\n        self.parent = parent\n        self.children = []\n        self.state = state\n\n    def backprop(self, value: float):\n        self.total += value\n        self.visit += 1\n        if self.parent is not None:\n            self.parent.backprop(value)\n\n\ndef enumerate_action_combinations(\n    max_count: int, num_options: int, cap: int = MAX_ACTION_COMBINATIONS\n) -> list[list[int]]:\n    """Enumerate index combinations of size `max_count` from `num_options` options.\n\n    Combinations are generated in lexicographic order (each a sorted list of distinct\n    indices in `range(num_options)`), and generation stops once `cap` combinations have\n    been produced.\n    """\n    actions = []\n    indices = list(range(max_count))\n    for _ in range(cap):\n        actions.append(indices.copy())\n        for i in range(len(indices)):\n            index = len(indices) - i - 1\n            if indices[index] < num_options - i - 1:\n                indices[index] += 1\n                for j in range(index + 1, len(indices)):\n                    indices[j] = indices[j - 1] + 1\n                break\n        else:\n            break\n    return actions\n\n\ndef build_children(node: Node, actions: list[list[int]], policy: list[float]) -> None:\n    """Attach softmax-weighted children to a node from a policy vector."""\n    total_prob = 0.0\n    for i in range(len(policy)):\n        p = math.exp(policy[i] * POLICY_TEMPERATURE)\n        node.children.append(Child(actions[i], p))\n        total_prob += p\n    for c in node.children:\n        c.prob /= total_prob\n\n\ndef select_child(current: Node, your_index: int):\n    """UCB-select the best child of ``current`` (None if it has none)."""\n    best, chosen = -1e18, None\n    c = EXPLORATION_C * math.sqrt(current.visit)\n    flip = current.state.observation.current.yourIndex != your_index\n    for child in current.children:\n        if child.node is None:\n            q = current.total / current.visit\n            visit = 0\n        else:\n            q = child.node.total / child.node.visit\n            visit = child.node.visit\n        if flip:\n            q = -q\n        u = q + c * child.prob / (1 + visit)\n        if u > best:\n            best, chosen = u, child\n    return chosen\n\n\nEvaluator = Callable[[Observation, list[list[int]]], tuple[float, list[float]]]\n\n\ndef create_node(parent: Node | None, search_state: SearchState, your_index: int, evaluate: Evaluator) -> Node:\n    node = Node(parent, search_state)\n    obs = search_state.observation\n    state = obs.current\n\n    if state.result >= 0:\n        if state.result == RESULT_DRAW:\n            node.value = 0.0\n        elif state.result == your_index:\n            node.value = 1.0\n        else:\n            node.value = -1.0\n        node.backprop(node.value)\n    else:\n        actions = enumerate_action_combinations(obs.select.maxCount, len(obs.select.option))\n        value, policy = evaluate(obs, actions)\n        v = value\n        if state.yourIndex != your_index:\n            v = -v\n        node.value = v\n        node.backprop(v)\n        build_children(node, actions, policy)\n    return node\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/search.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/search.py"), "w") as f:
    f.write(mcts_search_py_content)

# Copy cg directory
import glob


def find_cg_dir():
    candidates = [
        "/kaggle/input/pokemon-tcg-ai-battle/sample_submission/cg",
        "/kaggle/input/competitions/pokemon-tcg-ai-battle/sample_submission/cg",
        "/kaggle/input/**/sample_submission/cg",
        "/kaggle/input/**/cg",
    ]
    for pattern in candidates:
        for path in glob.glob(pattern, recursive=True):
            if os.path.isdir(path) and os.path.exists(os.path.join(path, "api.py")):
                return path
    raise FileNotFoundError("Could not find the official cg SDK directory.")


try:
    cg_src = find_cg_dir()
    cg_dst = os.path.join(WORKING_DIR, "cg")
    if os.path.exists(cg_dst):
        shutil.rmtree(cg_dst)
    shutil.copytree(cg_src, cg_dst, ignore=shutil.ignore_patterns("__pycache__", "*.pyc", "*.pyo"))
except Exception as e:
    print(f"Error copying cg: {e}")

# Create submission.tar.gz
# If there is a model weights file in the competition input or attached weight
# dataset, copy it into the submission archive.
for root, dirs, files in os.walk("/kaggle/input"):
    for file in files:
        if file in ("mcts.pth", "mcts_model.pth"):
            shutil.copy(os.path.join(root, file), os.path.join(WORKING_DIR, "mcts.pth"))
            break

submission_path = os.path.join(WORKING_DIR, "submission.tar.gz")


def submission_tar_filter(info):
    parts = info.name.split("/")
    if "__pycache__" in parts or info.name.endswith((".pyc", ".pyo")):
        return None
    return info


with tarfile.open(submission_path, "w:gz") as tar:
    items = ["main.py", "deck.csv", "cg"] + [
        "base_agent.py",
        "mcts/__init__.py",
        "mcts/agent.py",
        "mcts/encoding.py",
        "mcts/model.py",
        "mcts/search.py",
    ]
    if os.path.exists(os.path.join(WORKING_DIR, "mcts.pth")):
        items.append("mcts.pth")
    for item in items:
        full_path = os.path.join(WORKING_DIR, item)
        if os.path.exists(full_path):
            tar.add(full_path, arcname=item, filter=submission_tar_filter)

print(f"Created {submission_path}")
print(f"Size: {os.path.getsize(submission_path)} bytes")

